exercises.starterCode:
#include <stdio.h>

int main() {
    int arr[5] = {3, 1, 9, 2, 7};
    // Find and print the maximum value

    return 0;
}

exercises.solutionCode:
#include <stdio.h>

int main() {
    int arr[5] = {3, 1, 9, 2, 7};
    int max = arr[0];
    for (int i = 1; i < 5; i++) {
        if (arr[i] > max) {
            max = arr[i];
        }
    }
    printf("%d", max);
    return 0;
}
